<template>
    <div>
        <div style="margin-bottom: 20px">
            <el-input style="width: 240px" placeholder="请输入图书名称" v-model="params.bookName"></el-input>
<!--            <el-input style="width: 240px" placeholder="请输入图书的标准码" v-model="params.bookNo"></el-input>-->
            <el-input style="width: 240px" placeholder="请输入用户名称" v-model="params.userName"></el-input>

            <!--            表示有两种方式可以查询-->
            <el-button style="margin-left: 5px" type="primary"  round @click="load" ><i class="el-icon-search" ></i>搜索</el-button>
            <el-button style="margin-left: 5px" type="info" round @click="reset"><i class="el-icon-refresh-right" ></i>重置</el-button>
            <el-button style="margin-left: 5px" type="warning" round @click="change"><i class="el-icon-star-off" ></i>添加</el-button>
        </div>
        <el-table :data="tableData" stripe row-key="id" default-expand-all  size="medium">
<!--            <el-table-column prop="id" label="编号" width="80"></el-table-column>-->
            <el-table-column prop="bookName" label="图书名称" ></el-table-column>
<!--            <el-table-column prop="bookNo" label="标准码" width="80px"></el-table-column>-->
<!--            <el-table-column prop="userId" label="用户id" width="80px"></el-table-column>-->
            <el-table-column prop="userName" label="用户名称"></el-table-column>
<!--            <el-table-column prop="userPhone" label="用户联系方式" width="80px"></el-table-column>-->
            <el-table-column prop="number1" label="所借数量" ></el-table-column>
            <el-table-column prop="status" label="借出状态"></el-table-column>
            <el-table-column prop="note" label="过期提醒">
                <template v-slot="scope">
                    <el-tag type="success" v-if="scope.row.note === '正常' " >{{scope.row.note}}</el-tag>
                    <el-tag type="primary"  v-if="scope.row.note === '即将到期' ">{{scope.row.note}}</el-tag>
                    <el-tag type="warning"  v-if="scope.row.note === '已到期' ">{{scope.row.note}}</el-tag>
                    <el-tag type="danger"  v-if="scope.row.note === '已过期' ">{{scope.row.note}}</el-tag>
                </template>
            </el-table-column>
            <el-table-column label="管理">
                <template v-slot="scope">
                    <el-button type="primary" icon="el-icon-reading" @click="returnBooks(scope.row)" v-if="scope.row.status === '已借出' ">还书</el-button>
                </template>
            </el-table-column>
            <el-table-column label="操作" >
                <template v-slot="scope">
                    <!--                scope.row就是当前行数据-->
<!--                    <el-button type="success" v-if="!scope.row.pid" @click="handleAdd(scope.row)">添加二级分类</el-button>-->
<!--                    <el-button type="primary" @click="$router.push('/editBorrow?id=' + scope.row.id)">编辑</el-button>-->

                    <el-popconfirm
                            style="margin-left: 5px"
                            title="您确定删除吗？"
                            @confirm="del(scope.row.id)"
                    >
                        <el-button type="danger" icon="el-icon-delete" slot="reference">删除</el-button>
                    </el-popconfirm>
<!--                    <el-button type="primary" @click="" style="margin-left: 5px" @click="$router.push('/detailAdmin?id=' + scope.row.id)">详情</el-button>-->
<!--                    @click执行跳转页面和将数据带过去的操作，得到了id,需要后台UserController.java提供根据id查询的接口-->
                </template>
            </el-table-column>
        </el-table>

        <!--      分页-->
        <div style="margin-top: 20px">
            <el-pagination
                    background
                    :current-page="params.pageNum"
                    :page-size="params.pageSize"
                    layout="prev, pager, next"
                    @current-change="handleCurrentChange"
                    :total="total">
                <!--              tableData.length为当前表格的总个数-->
            </el-pagination>
        </div>

    </div>
</template>

<script>
    import request from "@/utils/request";
    import Cookies from 'js-cookie';
    export default {
        name: 'BorrowList',
        data(){
            return{
                admin: Cookies.get('admin') ? JSON.parse(Cookies.get('admin')) : {},
                tableData:[

                ],
                total: 0,
                params: {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',
                    bookNo: '',
                },
                rules:{
                    name: [
                        {required: true, message: '请输入图书名称', trigger: 'blur'},
                        {min: 3, max: 10, message: '长度在 3 到 10 个字符', trigger: 'blur'}
                    ],
                }
            }
        },
        created() {
            this.load()

        },
        methods: {
            
            load() {
                request.get('/borrow/page',{params: this.params}).then(res =>{
                    if(res.code === '200'){
                        this.tableData = res.data.list
                        this.total = res.data.total

                    }

                })
            },
            reset(){
                this.params = {
                    pageNum: 1,
                    pageSize: 10,
                    bookName: '',
                    bookNo:'',
                    userName: '',


                }
                this.load()
            },
            change(){
                this.$router.push('addBorrow');
            },
            handleCurrentChange(pageNum){
                //点击分页按钮触发分页
                this.params.pageNum = pageNum;
                this.load();
            },
            del(id){
                request.delete("/borrow/delete/"+id).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('删除成功');
                        this.load();
                    //    this.load()用来从新加载数据
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
            },
            returnBooks(row){
                request.post("/borrow/saveRet/",row).then(res =>{
                    if(res.code === '200'){
                      this.$notify.success('还书成功');
                      // this.load();
                     this.$router.push('/addNote?bookNo=' + row.bookNo + '&userId=' + row.userId);


                        //    this.load()用来从新加载数据
                    }else{
                        this.$notify.error(res.msg)
                    }
                })

            }
        }


    }
</script>
